import axios from 'axios';

const clientID = 'YOUR_CLIENT_ID';
const redirectURI = 'http://localhost:3000/callback'; // change this to your react app URL
const authorizationEndpoint = `https://accounts.google.com/o/oauth2/auth?response_type=token&client_id=${clientID}&redirect_uri=${encodeURIComponent(redirectURI)}&scope=email+profile&access_type=offline`;

function getAccessTokenFromURL() {
  const urlParams = new URLSearchParams(window.location.hash.slice(1));
  return urlParams.get('access_token');
}

axios.interceptors.push({
  request: (config) => {
    config.headers.Authorization = `Bearer ${getAccessTokenFromURL()}`;
    return config;
  }
});

function authenticate() {
  window.location.href = authorizationEndpoint;
}

// Call this function when the user clicks on a login button or link
authenticate();